pub trait Augmenter: Send + Sync {
    /// Human-readable name for metrics attribution (D62).
    fn name(&self) -> &str;

    /// Format search results into an augmented context with source citations.
    fn augment(
        &self,
        query: &str,
        results: &[SearchResult],
        budget: &TokenBudget,
    ) -> Result<AugmentedContext>;
}
